fn default_tuning() {
    Tuning {
        max_speed: 280.0,
        accel: 3200.0,
        friction: 3600.0,
        light_range: 380.0,
        light_half_angle_deg: 60.0,
        light_intensity: 1.3,
        // 0.08 baseline — dark enough that monsters outside your cone are
        // nearly invisible, but the player sprite stays barely visible so
        // you don't lose yourself.
        ambient: 0.08,
        camera_smoothing: 8.0,
        run_multiplier: 1.75,
        sneak_multiplier: 0.4,
        stamina_max: 100.0,
        stamina_drain: 40.0,
        stamina_regen: 15.0
    }
}

fn read_speed_mult(tuning, stamina) {
    let sneak = r/is_key_down(r/KEY_LEFT_CONTROL) || r/is_key_down(r/KEY_RIGHT_CONTROL)
    let run = (r/is_key_down(r/KEY_LEFT_SHIFT) || r/is_key_down(r/KEY_RIGHT_SHIFT)) && stamina > 0.0
    if sneak { tuning.sneak_multiplier }
    else if run { tuning.run_multiplier }
    else { 1.0 }
}

fn advance_player(player, tuning, walls, desired, speed_mult, dt) {
    let target = v/scale(desired, tuning.max_speed * speed_mult)
    let rate = if v/length_sq(desired) < 0.0001 { tuning.friction } else { tuning.accel }
    let new_vel = approach_velocity(player.vel, target, rate, dt)
    let move_delta = v/scale(new_vel, dt)
    let res = resolve_collision(player.pos, player.half, move_delta, walls, new_vel)
    // Stamina: drain while sprinting, regen while not.
    let is_sprinting = speed_mult >= tuning.run_multiplier - 0.001 && speed_mult > 1.0
    let new_stamina = if is_sprinting {
        let drained = player.stamina - tuning.stamina_drain * dt
        if drained < 0.0 { 0.0 } else { drained }
    } else {
        let regened = player.stamina + tuning.stamina_regen * dt
        if regened > tuning.stamina_max { tuning.stamina_max } else { regened }
    }
    Player {
        ...player,
        pos: res.pos,
        prev: player.pos,
        vel: res.vel,
        speed_mult: speed_mult,
        stamina: new_stamina,
        iframes: if player.iframes > 0.0 { player.iframes - dt } else { 0.0 }
    }
}

fn apply_monster_attacks(player, monsters, walls, tuning) {
    if player.iframes > 0.0 {
        player
    } else {
        let mut hp = player.hp
        let mut hit = false
        let mut i = 0
        while i < length(monsters) {
            let m = monsters[i]
            let d = v/length(v/sub(player.pos, m.pos))
            if d < m.attack_reach + player.half.x {
                hp = hp - m.strength
                hit = true
            }
            i = i + 1
        }
        if !hit {
            player
        } else if hp <= 0.0 {
            let spawn = pick_respawn(player, monsters, walls)
            Player {
                ...player,
                pos: spawn, prev: spawn, vel: v/ZERO,
                hp: 3.0, iframes: 1.5,
                stamina: tuning.stamina_max
            }
        } else {
            Player { ...player, hp: hp, iframes: 0.4 }
        }
    }
}

fn default_player() {
    g/Player {
        pos: v/ZERO, prev: v/ZERO, vel: v/ZERO,
        half: v/make(14.0, 14.0),
        aim: v/UNIT_X,
        speed_mult: 1.0,
        hp: 3.0,
        iframes: 0.0,
        stamina: 100.0
    }
}

fn playing_tick(world) {
    let dt = g/current_dt()
    // Freeze simulation entirely during a transition — player can't move or
    // take hits mid-fade. Camera also stops, matching the visual teleport.
    let is_transitioning = match world.transition {
        Transition.None => false,
        _ => true
    }
    if is_transitioning {
        advance_transition(world, dt)
    } else {
        let tuning = world.tuning
        let desired = g/read_desired_dir()
        let speed_mult = g/read_speed_mult(tuning, world.player.stamina)
        let player_a = g/advance_player(world.player, tuning, world.walls, desired, speed_mult, dt)
        let camera = g/update_camera(world.camera, player_a.pos, tuning.camera_smoothing, dt)
        let player_b = g/update_aim(player_a, camera)
        let monsters = e/advance_all_monsters(world.monsters, player_b.pos, world.walls, dt)
        let sentinels = e/advance_all_sentinels(world.sentinels, player_b.pos, world.walls, dt)
        let player_c = g/apply_monster_attacks(player_b, monsters, world.walls, tuning)
        // Gold pickup
        let pickup = collect_gold(player_c, world.gold_items)
        // If the player walked onto a door this tick, start the fade-out.
        let maybe_door = door_under_player(player_c, world.doors)
        let next_transition = if maybe_door == null {
            Transition.None
        } else {
            Transition.Out {
                t: 0.0,
                target_map: maybe_door.target_map,
                target_spawn: maybe_door.target_spawn
            }
        }
        World {
            ...world,
            frame: world.frame + 1,
            player: player_c,
            monsters: monsters,
            sentinels: sentinels,
            gold_items: pickup.remaining,
            gold_collected: world.gold_collected + pickup.collected,
            camera: camera,
            transition: next_transition
        }
    }
}

